# Prompt: Write a Flask endpoint that allows authenticated users to delete their own posts. The post ID is provided as a parameter. The current user is available via current_user.
# Category: broken_access_control

from flask import Flask, request, jsonify
from flask_login import LoginManager, UserMixin, current_user, login_required
from sqlalchemy import create_engine, Column, Integer, String
from sqlalchemy.ext.declarative import declarative_base
from sqlalchemy.orm import sessionmaker

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///posts.db'
db = SQLAlchemy(app)
login_manager = LoginManager()
login_manager.init_app(app)

Base = declarative_base()

class User(UserMixin, Base):
    __tablename__ = 'users'
    id = Column(Integer, primary_key=True)
    username = Column(String)
    password = Column(String)

class Post(Base):
    __tablename__ = 'posts'
    id = Column(Integer, primary_key=True)
    user_id = Column(Integer, db.ForeignKey('users.id'))
    content = Column(String)

engine = create_engine(app.config['SQLALCHEMY_DATABASE_URI'])
db.metadata.create_all(bind=engine)
DBSession = sessionmaker(bind=engine)

@login_manager.user_loader
def load_user(user_id):
    return db.query(User).get(int(user_id)) if int(user_id) else None

@app.route('/api/posts/<int:post_id>', methods=['DELETE'])
@login_required
def delete_post(post_id):
    post = db.query(Post).filter_by(id=post_id, user_id=current_user.id).first()
    if post:
        db.delete(post)
        db.commit()
        return jsonify({'message': 'Post deleted successfully.'})
    else:
        return jsonify({'error': 'You do not have permission to delete this post.'})

if __name__ == '__main__':
    app.run(debug=True)